<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    overflow: hidden;
    font-family: 'Ubuntu', 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
    user-select: none;
    height: 100vh;
    width: 100vw;
  }

  #desktop {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(135deg, #2c001e 0%, #4a0033 25%, #1a1a2e 60%, #16213e 100%);
    z-index: 0;
  }

  /* Top Bar */
  #topbar {
    position: fixed;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(15, 15, 15, 0.95);
    color: #e0e0e0;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    font-size: 13px;
    z-index: 1000;
    border-bottom: 1px solid rgba(255,255,255,0.08);
  }

  #topbar .left { display: flex; align-items: center; gap: 16px; }
  #topbar .ubuntu-logo { font-weight: bold; color: #e95420; letter-spacing: 1px; }
  #topbar .right { display: flex; align-items: center; gap: 14px; opacity: 0.85; }

  /* Taskbar / Dock */
  #taskbar {
    position: fixed;
    left: 0; top: 28px; bottom: 0;
    width: 56px;
    background: rgba(15, 15, 15, 0.88);
    backdrop-filter: blur(12px);
    display: flex;
    flex-direction: column;
    align-items: center;
    padding-top: 10px;
    gap: 6px;
    z-index: 999;
    border-right: 1px solid rgba(255,255,255,0.07);
  }

  #taskbar .dock-separator {
    width: 32px; height: 1px;
    background: rgba(255,255,255,0.12);
    margin: 4px 0;
  }

  .dock-btn {
    width: 42px; height: 42px;
    border-radius: 10px;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.15s ease;
    position: relative;
  }

  .dock-btn:hover { background: rgba(255,255,255,0.1); transform: scale(1.08); }
  .dock-btn:active { transform: scale(0.95); }

  .dock-btn svg { width: 26px; height: 26px; }

  #open-files { background: rgba(74, 127, 217, 0.35); }
  #open-notepad { background: rgba(98, 175, 98, 0.35); }

  .dock-btn .indicator {
    position: absolute;
    left: -4px; top: 50%; transform: translateY(-50%);
    width: 3px; height: 0;
    background: #e95420;
    border-radius: 0 2px 2px 0;
    transition: height 0.15s ease;
  }

  .dock-btn.active .indicator { height: 18px; }

  /* Windows */
  .app-window {
    position: absolute;
    background: #2d2d2d;
    border-radius: 10px;
    box-shadow: 0 12px 48px rgba(0,0,0,0.55), 0 0 0 1px rgba(255,255,255,0.06);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-width: 380px;
    min-height: 280px;
    z-index: 100;
  }

  .app-window.hidden { display: none !important; }

  .win-titlebar {
    height: 36px;
    background: #3a3a3a;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 10px;
    cursor: default;
    flex-shrink: 0;
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }

  .win-titlebar .title {
    color: #d0d0d0;
    font-size: 13px;
    font-weight: 500;
    pointer-events: none;
  }

  .win-controls { display: flex; gap: 7px; align-items: center; }

  .win-close {
    width: 24px; height: 24px;
    border-radius: 50%;
    border: none;
    background: #e95420;
    color: white;
    cursor: pointer;
    font-size: 13px;
    line-height: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.12s;
  }

  .win-close:hover { background: #c7431b; }

  .win-body {
    flex: 1;
    overflow-y: auto;
    color: #d4d4d4;
    font-size: 13px;
  }

  /* Scrollbar */
  .win-body::-webkit-scrollbar { width: 8px; }
  .win-body::-webkit-scrollbar-track { background: transparent; }
  .win-body::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.15); border-radius: 4px; }

  /* Files App */
  #files-window { width: 680px; height: 460px; }

  .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 12px;
    background: #353535;
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }

  #files-up {
    width: 30px; height: 30px;
    border-radius: 6px;
    border: none;
    background: rgba(255,255,255,0.07);
    color: #d0d0d0;
    cursor: pointer;
    font-size: 16px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.12s;
  }

  #files-up:hover { background: rgba(255,255,255,0.14); }

  #files-path {
    flex: 1;
    background: rgba(0,0,0,0.3);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 6px;
    padding: 5px 10px;
    color: #e95420;
    font-size: 13px;
    font-family: 'Ubuntu Mono', 'Consolas', monospace;
    outline: none;
  }

  #files-path:focus { border-color: rgba(233,84,32,0.5); }

  .files-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
    gap: 8px;
    padding: 14px;
  }

  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 12px 6px;
    border-radius: 8px;
    cursor: pointer;
    transition: background 0.12s;
    text-align: center;
    gap: 6px;
    min-height: 90px;
  }

  .fs-item:hover { background: rgba(255,255,255,0.07); }
  .fs-item:active { background: rgba(255,255,255,0.12); }

  .fs-item .icon { font-size: 36px; line-height: 1; }
  .fs-item .name { font-size: 11px; color: #c8c8c8; word-break: break-word; line-height: 1.3; }

  /* Notepad App */
  #notepad-window { width: 620px; height: 440px; }

  .notepad-tabs-bar {
    display: flex;
    align-items: center;
    background: #353535;
    border-bottom: 1px solid rgba(255,255,255,0.06);
    padding: 0 8px;
    min-height: 34px;
    gap: 2px;
  }

  #new-tab {
    width: 28px; height: 28px;
    border-radius: 5px;
    border: none;
    background: rgba(255,255,255,0.07);
    color: #d0d0d0;
    cursor: pointer;
    font-size: 16px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.12s;
    flex-shrink: 0;
  }

  #new-tab:hover { background: rgba(255,255,255,0.14); }

  #tabs {
    display: flex;
    align-items: center;
    gap: 2px;
    overflow-x: auto;
    flex: 1;
  }

  .tab {
    padding: 5px 14px;
    border-radius: 6px 6px 0 0;
    background: rgba(255,255,255,0.04);
    color: #a0a0a0;
    cursor: pointer;
    font-size: 12px;
    white-space: nowrap;
    transition: all 0.12s;
    display: flex;
    align-items: center;
    gap: 6px;
    border: 1px solid transparent;
    border-bottom: none;
    max-width: 160px;
  }

  .tab:hover { background: rgba(255,255,255,0.08); color: #d0d0d0; }

  .tab.active {
    background: #2d2d2d;
    color: #e95420;
    border-color: rgba(255,255,255,0.06);
    font-weight: 500;
  }

  .tab .close-tab {
    width: 16px; height: 16px;
    border-radius: 50%;
    border: none;
    background: transparent;
    color: #888;
    cursor: pointer;
    font-size: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    line-height: 1;
    transition: all 0.1s;
  }

  .tab .close-tab:hover { background: rgba(233,84,32,0.6); color: white; }

  #editor {
    width: 100%;
    flex: 1;
    resize: none;
    border: none;
    outline: none;
    background: #2d2d2d;
    color: #e8e8e8;
    font-family: 'Ubuntu Mono', 'Consolas', 'Courier New', monospace;
    font-size: 14px;
    line-height: 1.6;
    padding: 14px;
    tab-size: 4;
  }

  #editor::placeholder { color: #555; }

  /* Resize handle */
  .resize-handle {
    position: absolute;
    bottom: 0; right: 0;
    width: 16px; height: 16px;
    cursor: nwse-resize;
  }

  .resize-handle::after {
    content: '';
    position: absolute;
    bottom: 3px; right: 3px;
    width: 8px; height: 8px;
    border-right: 2px solid rgba(255,255,255,0.15);
    border-bottom: 2px solid rgba(255,255,255,0.15);
  }

  /* Window focus ring */
  .app-window.focused { box-shadow: 0 14px 56px rgba(0,0,0,0.6), 0 0 0 1px rgba(233,84,32,0.2); }

  /* Wallpaper pattern overlay */
  #desktop::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    background-image:
      radial-gradient(ellipse at 30% 20%, rgba(233,84,32,0.06) 0%, transparent 50%),
      radial-gradient(ellipse at 70% 80%, rgba(74,127,217,0.06) 0%, transparent 50%);
    pointer-events: none;
    z-index: 0;
  }

  /* Context hint */
  .desktop-hint {
    position: absolute;
    top: 50%; left: 50%;
    transform: translate(-50%, -50%);
    color: rgba(255,255,255,0.12);
    font-size: 18px;
    text-align: center;
    pointer-events: none;
    line-height: 1.6;
  }

  .desktop-hint span { display: block; font-size: 48px; margin-bottom: 8px; }
</style>
</head>
