<script>
(function() {
  'use strict';

  // ==================== CLOCK ====================
  function updateClock() {
    const now = new Date();
    const opts = { weekday: 'short', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' };
    document.getElementById('clock').textContent = now.toLocaleDateString('en-US', opts);
  }
  updateClock();
  setInterval(updateClock, 30000);

  // ==================== FILE SYSTEM DATA ====================
  const fileSystem = {
    '/': {
      bin: 'folder', etc: 'folder', home: 'folder', usr: 'folder', var: 'folder',
      tmp: 'folder', lib: 'folder', sbin: 'folder', dev: 'folder', proc: 'folder'
    },
    '/bin': {
      'bash': 'file', 'ls': 'file', 'cat': 'file', 'cp': 'file', 'mv': 'file',
      'rm': 'file', 'grep': 'file', 'find': 'file', 'chmod': 'file', 'chown': 'file'
    },
    '/etc': {
      'passwd': 'file', 'hostname': 'file', 'fstab': 'file', 'hosts': 'file',
      'resolv.conf': 'file', 'ssh': 'folder', 'apt': 'folder', 'xdg': 'folder'
    },
    '/etc/ssh': {
      'sshd_config': 'file', 'ssh_host_rsa_key': 'file', 'ssh_host_ed25519_key': 'file'
    },
    '/etc/apt': {
      'sources.list': 'file', 'apt.conf': 'file', 'preferences': 'file'
    },
    '/etc/xdg': {
      'autostart': 'folder'
    },
    '/home': {
      'user': 'folder', 'guest': 'folder'
    },
    '/home/user': {
      'Documents': 'folder', 'Downloads': 'folder', 'Pictures': 'folder',
      'Music': 'folder', 'Videos': 'folder', '.bashrc': 'file', '.profile': 'file',
      '.ssh': 'folder'
    },
    '/home/user/Documents': {
      'readme.txt': 'file', 'notes.md': 'file', 'todo.txt': 'file',
      'projects': 'folder'
    },
    '/home/user/Documents/projects': {
      'Makefile': 'file', 'src': 'folder', 'README': 'file'
    },
    '/home/user/Documents/projects/src': {
      'main.c': 'file', 'utils.h': 'file', 'utils.c': 'file'
    },
    '/home/user/Downloads': {
      'ubuntu-22.04.iso': 'file', 'archive.tar.gz': 'file', 'photo.jpg': 'file'
    },
    '/home/user/Pictures': {
      'wallpaper.png': 'file', 'screenshot.png': 'file', 'avatar.jpg': 'file'
    },
    '/home/user/Music': {
      'playlist.m3u': 'file', 'song.mp3': 'file'
    },
    '/home/user/Videos': {
      'tutorial.mp4': 'file'
    },
    '/home/user/.ssh': {
      'id_rsa': 'file', 'id_rsa.pub': 'file', 'known_hosts': 'file'
    },
    '/home/guest': {
      'Desktop': 'folder'
    },
    '/home/guest/Desktop': {},
    '/usr': {
      'bin': 'folder', 'lib': 'folder', 'share': 'folder', 'local': 'folder'
    },
    '/usr/bin': {
      'python3': 'file', 'node': 'file', 'gcc': 'file', 'make': 'file', 'git': 'file'
    },
    '/usr/lib': {},
    '/usr/share': {
      'applications': 'folder', 'doc': 'folder'
    },
    '/usr/local': {
      'bin': 'folder', 'lib': 'folder'
    },
    '/var': {
      'log': 'folder', 'cache': 'folder', 'tmp': 'folder', 'www': 'folder'
    },
    '/var/log': {
      'syslog': 'file', 'auth.log': 'file', 'kern.log': 'file'
    },
    '/var/cache': {},
    '/var/tmp': {},
    '/var/www': {
      'index.html': 'file', 'css': 'folder', 'js': 'folder'
    },
    '/tmp': {
      '.X11-unix': 'folder', 'pulse': 'folder'
    },
    '/lib': {
      'x86_64-linux-gnu': 'folder'
    },
    '/sbin': {
      'init': 'file', 'fdisk': 'file'
    },
    '/dev': {
      'sda': 'file', 'sdb': 'file', 'null': 'file', 'zero': 'file'
    },
    '/proc': {
      'cpuinfo': 'file', 'meminfo': 'file', 'version': 'file'
    }
  };

  // ==================== FILES APP ====================
  const filesWindow = document.getElementById('files-window');
  const filesGrid = document.getElementById('files-grid');
  const filesPathInput = document.getElementById('files-path');
  const filesUpBtn = document.getElementById('files-up');
  let currentPath = '/';

  function getIcon(name, type) {
    if (type === 'folder') return '📁';
    const ext = name.split('.').pop().toLowerCase();
    const iconMap = {
      txt: '📄', md: '📝', pdf: '📕', jpg: '🖼️', jpeg: '🖼️', png: '🖼️', gif: '🖼️', svg: '🖼️',
      mp3: '🎵', wav: '🎵', m4a: '🎵', flac: '🎵',
      mp4: '🎬', avi: '🎬', mkv: '🎬', mov: '🎬',
      iso: '💿', tar: '📦', gz: '📦', zip: '📦', '7z': '📦',
      sh: '⚙️', c: '🔧', h: '🔧', py: '🐍', js: '🟨', html: '🌐', css: '🎨',
      conf: '⚙️', list: '📋', log: '📊', m3u: '🎶'
    };
    return iconMap[ext] || '📄';
  }

  function renderFiles() {
    filesGrid.innerHTML = '';
    const entries = fileSystem[currentPath];
    if (!entries) {
      filesPathInput.value = currentPath;
      return;
    }

    // Sort: folders first, then files alphabetically
    const sorted = Object.entries(entries).sort((a, b) => {
      if (a[1] === 'folder' && b[1] !== 'folder') return -1;
      if (a[1] !== 'folder' && b[1] === 'folder') return 1;
      return a[0].localeCompare(b[0]);
    });

    for (const [name, type] of sorted) {
      const item = document.createElement('div');
      item.className = 'fs-item';
      item.innerHTML = `<span class="icon">${getIcon(name, type)}</span><span class="name">${name}</span>`;

      if (type === 'folder') {
        let clickCount = 0;
        let timer = null;
        item.addEventListener('click', function() {
          clickCount++;
          if (clickCount === 1) {
            timer = setTimeout(function() {
              // Single click: select (visual feedback only)
              item.style.background = 'rgba(233,84,32,0.15)';
              setTimeout(() => { item.style.background = ''; }, 200);
              clickCount = 0;
            }, 250);
          } else if (clickCount === 2) {
            clearTimeout(timer);
            // Double-click: navigate into folder
            const newPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
            if (fileSystem[newPath] !== undefined) {
              currentPath = newPath;
              filesPathInput.value = currentPath;
              renderFiles();
            }
            clickCount = 0;
          }
        });

        item.addEventListener('dblclick', function(e) {
          e.preventDefault();
          clearTimeout(timer);
          const newPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
          if (fileSystem[newPath] !== undefined) {
            currentPath = newPath;
            filesPathInput.value = currentPath;
            renderFiles();
          }
          clickCount = 0;
        });
      }

      filesGrid.appendChild(item);
    }

    filesPathInput.value = currentPath;
  }

  filesUpBtn.addEventListener('click', function() {
    if (currentPath === '/') return;
    const parts = currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath = '/' + parts.join('/') || '/';
    renderFiles();
  });

  // ==================== NOTEPAD APP ====================
  const notepadWindow = document.getElementById('notepad-window');
  const tabsContainer = document.getElementById('tabs');
  const newTabBtn = document.getElementById('new-tab');
  const editor = document.getElementById('editor');

  let tabs = [];
  let activeTabIndex = -1;

  function loadTabs() {
    try {
      const saved = localStorage.getItem('notepad-tabs');
      if (saved) {
        tabs = JSON.parse(saved);
      }
    } catch(e) {}
    if (!tabs.length) {
      tabs.push({ name: 'Untitled', content: '' });
    }
    activeTabIndex = 0;
    renderTabs();
    editor.value = tabs[activeTabIndex].content || '';
  }

  function saveTabs() {
    try {
      localStorage.setItem('notepad-tabs', JSON.stringify(tabs));
    } catch(e) {}
  }

  function renderTabs() {
    tabsContainer.innerHTML = '';
    tabs.forEach(function(tab, i) {
      const el = document.createElement('div');
      el.className = 'tab' + (i === activeTabIndex ? ' active' : '');
      el.innerHTML = `<span class="tab-name">${escapeHtml(tab.name)}</span><button class="close-tab" data-index="${i}">✕</button>`;

      el.addEventListener('click', function(e) {
        if (e.target.classList.contains('close-tab')) return;
        activeTabIndex = i;
        renderTabs();
        editor.value = tabs[i].content || '';
      });

      const closeBtn = el.querySelector('.close-tab');
      closeBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        if (tabs.length <= 1) return; // Don't close last tab
        const wasActive = i === activeTabIndex;
        tabs.splice(i, 1);
        if (wasActive) {
          activeTabIndex = Math.min(activeTabIndex, tabs.length - 1);
        } else if (i < activeTabIndex) {
          activeTabIndex--;
        }
        renderTabs();
        editor.value = tabs[activeTabIndex].content || '';
        saveTabs();
      });

      tabsContainer.appendChild(el);
    });
  }

  function escapeHtml(str) {
    const div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
  }

  newTabBtn.addEventListener('click', function() {
    const num = tabs.length + 1;
    tabs.push({ name: 'Untitled-' + num, content: '' });
    activeTabIndex = tabs.length - 1;
    renderTabs();
    editor.value = '';
    saveTabs();
  });

  // Save on input (debounced)
  let saveTimeout = null;
  editor.addEventListener('input', function() {
    if (activeTabIndex >= 0 && activeTabIndex < tabs.length) {
      tabs[activeTabIndex].content = editor.value;
      clearTimeout(saveTimeout);
      saveTimeout = setTimeout(saveTabs, 400);
    }
  });

  // ==================== WINDOW MANAGEMENT ====================
  const filesOpenBtn = document.getElementById('open-files');
  const notepadOpenBtn = document.getElementById('open-notepad');

  function showWindow(win) {
    win.classList.remove('hidden');
    focusWindow(win);
  }

  function hideWindow(win) {
    win.classList.add('hidden');
  }

  function focusWindow(win) {
    // Unfocus all
    document.querySelectorAll('.app-window').forEach(w => w.classList.remove('focused'));
    win.classList.add('focused');
    updateDockIndicators();
  }

  function updateDockIndicators() {
    const filesOpen = filesWindow.classList.contains('hidden') ? '' : 'active';
    const notepadOpen = notepadWindow.classList.contains('hidden') ? '' : 'active';
    filesOpenBtn.className = 'dock-btn ' + filesOpen;
    notepadOpenBtn.className = 'dock-btn ' + notepadOpen;
  }

  // Open buttons
  filesOpenBtn.addEventListener('click', function() {
    showWindow(filesWindow);
    renderFiles();
  });

  notepadOpenBtn.addEventListener('click', function() {
    showWindow(notepadWindow);
    if (tabs.length === 0) loadTabs();
    else {
      renderTabs();
      editor.value = tabs[activeTabIndex].content || '';
    }
  });

  // Close buttons
  document.querySelectorAll('.win-close').forEach(function(btn) {
    btn.addEventListener('click', function() {
      const win = this.closest('.app-window');
      hideWindow(win);
      updateDockIndicators();
    });
  });

  // Click window to focus
  document.querySelectorAll('.app-window').forEach(function(win) {
    win.addEventListener('mousedown', function() {
      focusWindow(this);
    });
  });

  // ==================== DRAGGABLE WINDOWS ====================
  function makeDraggable(win, titlebar) {
    let isDragging = false;
    let startX, startY, origX, origY;

    titlebar.addEventListener('mousedown', function(e) {
      if (e.target.classList.contains('win-close')) return;
      isDragging = true;
      startX = e.clientX;
      startY = e.clientY;
      const rect = win.getBoundingClientRect();
      origX = rect.left;
      origY = rect.top;
      win.style.transition = 'none';
      focusWindow(win);
      e.preventDefault();
    });

    document.addEventListener('mousemove', function(e) {
      if (!isDragging) return;
      const dx = e.clientX - startX;
      const dy = e.clientY - startY;
      win.style.left = (origX + dx) + 'px';
      win.style.top = (origY + dy) + 'px';
    });

    document.addEventListener('mouseup', function() {
      if (isDragging) {
        isDragging = false;
        win.style.transition = '';
      }
    });
  }

  makeDraggable(filesWindow, filesWindow.querySelector('.win-titlebar'));
  makeDraggable(notepadWindow, notepadWindow.querySelector('.win-titlebar'));

  // ==================== RESIZABLE WINDOWS ====================
  function makeResizable(win) {
    const handle = win.querySelector('.resize-handle');
    if (!handle) return;
    let isResizing = false;
    let startX, startY, startW, startH;

    handle.addEventListener('mousedown', function(e) {
      isResizing = true;
      startX = e.clientX;
      startY = e.clientY;
      const rect = win.getBoundingClientRect();
      startW = rect.width;
      startH = rect.height;
      win.style.transition = 'none';
      focusWindow(win);
      e.preventDefault();
      e.stopPropagation();

      function onMove(e) {
        if (!isResizing) return;
        const w = Math.max(380, startW + (e.clientX - startX));
        const h = Math.max(280, startH + (e.clientY - startY));
        win.style.width = w + 'px';
        win.style.height = h + 'px';
      }

      function onUp() {
        isResizing = false;
        win.style.transition = '';
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
      }

      document.addEventListener('mousemove', onMove);
      document.addEventListener('mouseup', onUp);
    });
  }

  makeResizable(filesWindow);
  makeResizable(notepadWindow);

  // ==================== INIT ====================
  renderFiles();
  loadTabs();
  updateDockIndicators();

})();
</script>
